sequence.script:
var value = String(mc.getProperty('requested.subscriber') || '');
var masked = value;
if (value.length > 7) {
    masked = value.substring(0, 3) + '******' + value.substring(value.length - 4);
} else if (value.length > 0) {
    masked = '****';
}
var persona = String(mc.getProperty('persona') || '');
var purpose = String(mc.getProperty('requested.purpose') || '');
var fullAllowed =
    (persona === 'operations' || persona === 'platform_administrator') &&
    purpose === 'fraud-investigation' &&
    String(mc.getProperty('requested.data.access') || '') === 'FULL';
mc.setProperty('returned.subscriber', fullAllowed ? value : masked);
mc.setProperty('subscriber.masked', fullAllowed ? 'false' : 'true');
